     private void reflectionAppend(final Object lhs, final Object rhs, final Class<?> clazz) {
         if (isRegistered(lhs, rhs)) {
@@ -1029,7 +1032,6 @@
         try {
             register(lhs, rhs);
             final Field[] fields = clazz.getDeclaredFields();
